def main():
    n, k = map(int, input().split())
    mod = 10**9 + 7
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    for j in range(1, n + 1):
        dp[1][j] = 1
    for i in range(1, n + 1):
        dp[i][1] = 1
    for i in range(2, n + 1):
        for j in range(2, n + 1):
            dp[i][j] = (dp[i - 1][j] + dp[i][j - 1]) % mod
    ans = 0
    for i in range(1, n + 1):
        for j in range(1, n + 1):
            ans += dp[i][j] * (k - i + 1) * (k - j + 1)
            ans %= mod
    print(ans)


main()
